import stylesText from './weight-chart.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { HealthService } from '../../../services/health.service.js';
import { appTodayPlainDate } from '../../../services/app-timezone.service.js';
import { dailyAverageSeries, movingAverage } from '@motivation/shared';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { safeExec } from '../../../utils/safe-exec.js';

const styles = cssStyleSheet(stylesText);
const log = createComponentLogger('health/weight-chart');

const SVG_NS = 'http://www.w3.org/2000/svg';

// `.hidden` is an HTMLElement property; SVG elements aren't typed with it (they
// still honor the `[hidden]` attribute via the cssStyleSheet display:none rule).
function setHidden(el: Element, hidden: boolean): void {
    el.toggleAttribute('hidden', hidden);
}

const VIEW_W = 320;
const VIEW_H = 160;
const MARGIN = 14;
const TREND_WINDOW = 7; // 7-day (7-point) trailing moving average — see shared/weight-trend.ts

/** Selectable look-back ranges. "All" is a bounded 5-year window — never fetch-all. */
const RANGES: ReadonlyArray<{ label: string; days: number }> = [
    { label: '30d', days: 30 },
    { label: '90d', days: 90 },
    { label: '1y', days: 365 },
    { label: 'All', days: 1825 },
];
const DEFAULT_RANGE_DAYS = 90;

const template = document.createElement('template');
template.innerHTML = `
    <div class="wc">
        <div class="wc__ranges" data-testid="weight-chart-ranges"></div>
        <p class="screen-loading" hidden>Loading…</p>
        <pre class="screen-error" hidden></pre>
        <button class="screen-retry" type="button" hidden>Retry</button>
        <p class="wc__empty" data-testid="weight-chart-empty" hidden>No weight logged in this range.</p>
        <svg class="wc__svg" data-testid="weight-chart-svg" viewBox="0 0 ${VIEW_W} ${VIEW_H}" preserveAspectRatio="none" hidden>
            <polyline class="wc__trend" data-testid="weight-chart-trend" fill="none" hidden></polyline>
            <g class="wc__points" data-testid="weight-chart-points"></g>
            <text class="wc__label wc__label--hi" data-testid="weight-chart-max" x="2" y="12"></text>
            <text class="wc__label wc__label--lo" data-testid="weight-chart-min" x="2" y="${VIEW_H - 4}"></text>
        </svg>
    </div>
`;

/**
 * Story 171 — weight over time: raw daily points + a smoothed trend line on an
 * auto-fit (non-zero) baseline, the visual idiom body weight needs (vs the
 * calorie chart's bars-from-zero). Hand-rolled SVG, no charting dependency.
 * Reductions/smoothing are pure shared helpers; this component only maps to
 * coordinates and renders. Fetches its own range and degrades per-component.
 */
export class WeightChart extends HTMLElement {
    private rangeDays = DEFAULT_RANGE_DAYS;
    private rangesEl: HTMLElement | null = null;
    private svgEl: SVGSVGElement | null = null;
    private trendEl: SVGPolylineElement | null = null;
    private pointsEl: SVGGElement | null = null;
    private maxLabel: SVGTextElement | null = null;
    private minLabel: SVGTextElement | null = null;
    private emptyEl: HTMLElement | null = null;
    private loadingEl: HTMLElement | null = null;
    private errorEl: HTMLElement | null = null;
    private retryEl: HTMLButtonElement | null = null;
    /** Exposed so a host/test can await the in-flight load (mirrors the other charts). */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.shadowRoot!.adoptedStyleSheets = [styles];
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        const root = this.shadowRoot!;
        this.rangesEl = root.querySelector('[data-testid="weight-chart-ranges"]');
        this.svgEl = root.querySelector<SVGSVGElement>('[data-testid="weight-chart-svg"]');
        this.trendEl = root.querySelector<SVGPolylineElement>('[data-testid="weight-chart-trend"]');
        this.pointsEl = root.querySelector<SVGGElement>('[data-testid="weight-chart-points"]');
        this.maxLabel = root.querySelector<SVGTextElement>('[data-testid="weight-chart-max"]');
        this.minLabel = root.querySelector<SVGTextElement>('[data-testid="weight-chart-min"]');
        this.emptyEl = root.querySelector('[data-testid="weight-chart-empty"]');
        this.loadingEl = root.querySelector('.screen-loading');
        this.errorEl = root.querySelector('.screen-error');
        this.retryEl = root.querySelector<HTMLButtonElement>('.screen-retry');
    }

    setLoading(): void {
        if (this.loadingEl) this.loadingEl.hidden = false;
        if (this.errorEl) this.errorEl.hidden = true;
        if (this.retryEl) this.retryEl.hidden = true;
    }
    setError(err: unknown): void {
        if (this.loadingEl) this.loadingEl.hidden = true;
        if (this.errorEl) {
            this.errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
            this.errorEl.hidden = false;
        }
        if (this.retryEl) this.retryEl.hidden = false;
        if (this.svgEl) setHidden(this.svgEl, true);
        if (this.emptyEl) this.emptyEl.hidden = true;
    }
    clearStatus(): void {
        if (this.loadingEl) this.loadingEl.hidden = true;
        if (this.errorEl) this.errorEl.hidden = true;
        if (this.retryEl) this.retryEl.hidden = true;
    }

    connectedCallback(): void {
        this.renderRangeButtons();
        this.retryEl?.addEventListener('click', () => this.refresh());
        this.refresh();
    }

    private renderRangeButtons(): void {
        if (!this.rangesEl) return;
        this.rangesEl.replaceChildren();
        for (const range of RANGES) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'wc__range';
            btn.textContent = range.label;
            btn.dataset.days = String(range.days);
            btn.setAttribute('aria-pressed', String(range.days === this.rangeDays));
            btn.addEventListener('click', () => {
                if (this.rangeDays === range.days) return;
                this.rangeDays = range.days;
                this.renderRangeButtons();
                this.refresh();
            });
            this.rangesEl.appendChild(btn);
        }
    }

    refresh(): void {
        this.loadPromise = safeExec(this, log, () => this.load());
    }

    private async load(): Promise<void> {
        const to = appTodayPlainDate();
        const from = to.subtract({ days: this.rangeDays });
        const entries = await HealthService.fetchWeightByDateRange(from.toString(), to.toString());
        this.render(dailyAverageSeries(entries));
    }

    private render(series: { date: string; weight_kg: number }[]): void {
        if (!this.svgEl || !this.pointsEl || !this.trendEl || !this.emptyEl) return;
        this.pointsEl.replaceChildren();

        if (series.length === 0) {
            setHidden(this.svgEl, true);
            this.emptyEl.hidden = false;
            return;
        }
        this.emptyEl.hidden = true;
        setHidden(this.svgEl, false);

        const weights = series.map((p) => p.weight_kg);
        const min = Math.min(...weights);
        const max = Math.max(...weights);
        // Auto-fit, non-zero baseline with padding; guard the all-equal case.
        const pad = max === min ? 1 : (max - min) * 0.15;
        const lo = min - pad;
        const hi = max + pad;

        const plotW = VIEW_W - 2 * MARGIN;
        const plotH = VIEW_H - 2 * MARGIN;
        const x = (i: number) => series.length === 1 ? MARGIN + plotW / 2 : MARGIN + (i / (series.length - 1)) * plotW;
        const y = (w: number) => MARGIN + (1 - (w - lo) / (hi - lo)) * plotH;

        for (let i = 0; i < series.length; i++) {
            const c = document.createElementNS(SVG_NS, 'circle');
            c.setAttribute('cx', x(i).toFixed(1));
            c.setAttribute('cy', y(weights[i]).toFixed(1));
            c.setAttribute('r', '2.5');
            c.setAttribute('class', 'wc__point');
            this.pointsEl.appendChild(c);
        }

        // Trend line only with ≥2 points — never fake a line through one point.
        if (series.length >= 2) {
            const trend = movingAverage(weights, TREND_WINDOW);
            this.trendEl.setAttribute('points', trend.map((t, i) => `${x(i).toFixed(1)},${y(t).toFixed(1)}`).join(' '));
            setHidden(this.trendEl, false);
        } else {
            setHidden(this.trendEl, true);
        }

        if (this.maxLabel) this.maxLabel.textContent = `${Math.round(max * 10) / 10} kg`;
        if (this.minLabel) this.minLabel.textContent = `${Math.round(min * 10) / 10} kg`;
    }
}

if (!customElements.get('weight-chart')) {
    customElements.define('weight-chart', WeightChart);
}
