import type { DailyWeightSummary, WeightEntry } from '../types/health.js';

/**
 * Story 171 — pure helpers for the weight trend chart (and reusable elsewhere).
 *
 * Body weight swings ±1–2 kg day-to-day on water / gut contents, so the signal
 * is the smoothed trend, not the raw points. These two functions are the only
 * computation the chart needs; keeping them pure makes them unit-testable
 * without a DOM or DB.
 */

/**
 * Collapse raw weigh-ins to one representative value per date — the daily
 * **average** — ascending by date. Mirrors the server-side SQL reduction
 * (`weightEntriesRepository.getDateRangeSummary`, story 172); this JS version
 * runs client-side over the already-fetched raw entries so the chart needs no
 * extra endpoint. Same concept, different runtime.
 */
export function dailyAverageSeries(entries: WeightEntry[]): DailyWeightSummary[] {
    const byDate = new Map<string, { sum: number; count: number }>();
    for (const entry of entries) {
        const acc = byDate.get(entry.date) ?? { sum: 0, count: 0 };
        acc.sum += entry.weight_kg;
        acc.count += 1;
        byDate.set(entry.date, acc);
    }
    return [...byDate.entries()]
        .map(([date, { sum, count }]) => ({ date, weight_kg: sum / count }))
        .sort((a, b) => a.date.localeCompare(b.date));
}

/**
 * Trailing moving average over a series of daily values. Index `i` is the mean
 * of the up-to-`window` values ending at `i`, so the line starts at the first
 * point (partial window) rather than leaving a gap. Operates on **points**
 * (one per present day), so gaps in logging compress — a reasonable smoothing
 * for sparse weigh-ins; EMA is an easy swap if the MA feels laggy.
 */
export function movingAverage(values: number[], window: number): number[] {
    if (window < 1) throw new Error('movingAverage: window must be >= 1');
    const out: number[] = [];
    for (let i = 0; i < values.length; i++) {
        const start = Math.max(0, i - window + 1);
        const slice = values.slice(start, i + 1);
        out.push(slice.reduce((sum, v) => sum + v, 0) / slice.length);
    }
    return out;
}
